searchBook.requestInfo:
@js:
var url = config.host + "/novel/list?searchType=1&keyword=" + encodeURIComponent(params.keyWord) + "&page=" + (params.pageIndex || 1);
return {
  url: url,
  webView: true,
  webViewJsDelay: 2.5,
  webViewSkipUrls: [
    "cloudflareinsights.com",
    "googletagmanager.com",
    "google-analytics.com",
    "aizhantj.com",
    "doubleclick.net"
  ],
  httpHeaders: config.httpHeaders
};

