chapterContent.content:
//div[contains(@class,"article")] |@js:
var t = String(result || "").trim();
if (!t || /此章节为付费章节/.test(t)) {
  return "（本章需登录/VIP 或付费解锁，游客仅可阅读免费章节）";
}
return t;
